```javascript
class FenwickTree {
    constructor(size) {
        this.n = size;
        this.tree = new Array(this.n + 1).fill(0);
    }

    update(pos, delta) {
        while (pos <= this.n) {
            this.tree[pos] += delta;
            pos += pos & -pos;
        }
    }

    query(pos) {
        let res = 0;
        while (pos > 0) {
            res += this.tree[pos];
            pos -= pos & -pos;
        }
        return res;
    }
}

function computeDepth(x) {
    let depth = 0;
    while (x !== 1) {
        x = x.toString(2).split('1').length - 1;
        depth++;
    }
    return depth;
}

function solve(nums, queries) {
    const n = nums.length;
    const depths = nums.map(x => computeDepth(x));
    const ft = Array(7).fill(0).map(() => new FenwickTree(n));
    for (let i = 0; i < n; i++) {
        const d = depths[i];
        ft[d].update(i + 1, 1);
    }
    const answer = [];
    for (const q of queries) {
        if (q[0] === 1) {
            const l = q[1];
            const r = q[2];
            const k = q[3];
            const sum_r = ft[k].query(r + 1);
            const sum_l = ft[k].query(l);
            answer.push(sum_r - sum_l);
        } else {
            const idx = q[1];
            const val = q[2];
            const old_d = depths[idx];
            const new_d = computeDepth(val);
            ft[old_d].update(idx + 1, -1);
            ft[new_d].update(idx + 1, 1);
            depths[idx] = new_d;
            nums[idx] = val;
        }
    }
    return answer;
}
